(window.webpackJsonp=window.webpackJsonp||[]).push([[10],{"5Epl":function(e,a,o){"use strict";o.d(a,"a",(function(){return p}));var i=o("q1tI"),n=o.n(i),r=o("R/WZ"),t=o("ofer"),l=Object(r.a)({figure:{margin:"0"},image:{width:"100%",maxHeight:"700px",borderRadius:"7px",display:"block",margin:"auto"}});function p(e){var a=e.src,o=e.caption,i=e.center,r=l();return n.a.createElement("figure",{className:r.figure},n.a.createElement("img",{src:a,alt:o,className:r.image,style:i?{width:"auto",margin:"auto"}:null}),n.a.createElement(t.a,{variant:"caption",paragraph:!0,align:i?"center":"left"},o))}},"Frg/":function(e,a,o){e.exports=o.p+"static/vzorci-9128c427a95f0c62756de339c1b89420.jpg"},Qk3k:function(e,a,o){e.exports=o.p+"static/talilnik-19723c54911968c2a456bea888e220b9.jpg"},"t/8H":function(e,a,o){e.exports=o.p+"static/raziskave-e0201317f37090e7de6b4956efcbdd07.jpg"},vfis:function(e,a,o){"use strict";o.r(a);var i=o("q1tI"),n=o.n(i),r=o("ofer"),t=o("mc/u"),l=o("5Epl"),p=o("t/8H"),s=o.n(p),j=o("Qk3k"),d=o.n(j),k=o("Frg/"),v=o.n(k);a.default=function(){return n.a.createElement(t.a,{title:"Talilniško območje"},n.a.createElement(r.a,{variant:"body1",paragraph:!0},"Med najpomembnejše dejavnosti tukajšnjih prazgodovinskih prebivalcev štejemo taljenje železa in kovaštvo. Sledovi teh dejavnosti so prisotni tako znotraj naselja, kjer lahko na tleh najdemo kovaško žlindro, predvsem pa na južnem pobočju Cvingerja. Nekje na polovici poti med naseljem in gomilnim grobiščem Branževec so leta 1988 strokovnjaki med terenskimi pregledi na površini našli večje količine železove žlindre. Ker so bili vmes tudi koščki prežgane ilovice, je vse kazalo na to, da se pod gozdnim humusom skrivajo ostanki železnodobnih talilnih peči."),n.a.createElement(r.a,{variant:"body1",paragraph:!0},"Domnevo so takrat preverili z manjšim izkopom (3 × 4 m) na sredini prostora, kjer je bila koncentracija najdb na površini največja. Sondiranje je domneve potrdilo, saj se je tik pod površjem nahajala večja količina železove žlindre in prežgane ilovice, ki je ležala raztresena po vsej površini izkopa. Na nivoju oranžno-rdeče ilovice (50‒60 cm pod površjem) so se pokazali jasni obrisi dvanajstih železarskih talilnih peči. Ležale so tesno skupaj, dve sta se celo dotikali. Nadaljnji izkop je pokazal, da gre za jame, vkopane v ilovnata tla. Njihova notranjost je bila večinoma močno ožgana in zapolnjena s temnejšo zemljo, kosi železove žlindre, lesnim ogljem in ponekod tudi prežganim kamenjem. Ohranili so se le spodnji deli peči z ostenjem, ki je bilo izdelano iz gline. V tlorisu so bile peči povečini okroglih oblik s premerom od 40 do 70 cm, le ena je merila 80 × 100 cm."),n.a.createElement(l.a,{src:v.a,caption:"Oblikovni in utežnostni prikaz različnih oblik železa."}),n.a.createElement(r.a,{variant:"body1",paragraph:!0},"Arheološko sondiranje na Branževcu je torej potrdilo domnevo, da je tu v železni dobi stal talilniški obrat. Sledile so prve nedestruktivne geofizikalne raziskave (magnetna metoda, 1997), ki so pokazale, da se je ta raztezal na približno 0,6 ha velikem prostoru, na katerem so nekdaj postavili več sto talilnih peči. Pridobivanje železa je v tistem času torej potekalo izven naselja, pridobljeno surovo železo (volk) pa so predelovali in kovali tudi znotraj naselja."),n.a.createElement(l.a,{src:d.a,caption:"Prerez skozi naloženo in dogorelo jaškasto talilno peč z jamo za žlindro."}),n.a.createElement(r.a,{variant:"body1",paragraph:!0},"Od leta 2013 do 2018 so na Branževcu potekale dodatne arheološke raziskave, kjer so bile uporabljene najsodobnejše geofizikalne metode. Na podlagi njihovih rezultatov je bila narejen še en arheološki izkop, ki je ponovno pokazal na gosto razporeditev talinih peči. Nadalje je pokazal, da so bile nekatere peči uporabljene večkrat. Ko je stara peč postala neuporabna, so jo včasih celo delno pre-uporabili za postavitev nove peči, ali pa so to sezidali v njeni neposredni bližini."),n.a.createElement(l.a,{src:s.a,caption:"Raziskave v arheološkem izkopu (sondi) na talilniškem območju. Foto Matija Črešnar."}),n.a.createElement(r.a,{variant:"body1",paragraph:!0},"Ena od peči je bila ob tem uspešno datirana z magnetno datacijsko metodo (prvič uporabljena pri nas). Njen rezultat je v skladu z arheološkimi dokazi in kaže na zadnjo uporabo peči v času 640–370 pr. n. št. Uspešna datacija je pomembna, saj na območju taljenja ni bilo odkritih za datiranje uporabnih keramičnih ali kovinskih najdb, radiokarbonsko datiranje oglja pa je za čas starejše železne dobe uporabno le omejeno."))}}}]);
